-          found_bucket = tx;
-          found_remaining_k = remaining_k - count_gt;
-        }
-      }
-      __syncthreads();
-
-      // Update local caches (all CTAs have same values)
-      if (tx == 0) {
-        prefix_cache = prefix | (found_bucket << shift);
-        remaining_k_cache = found_remaining_k;
-      }
-      __syncthreads();
-    }
